/**
 * 関西丸進運輸（株） 大阪南営業所 — 運賃・請求／売掛管理データ
 *
 * Server-safe module (NO "use client"): plain data + pure helpers that a Server
 * Component imports to precompute derived totals. Function props (formatters,
 * cell renderers) live in the client BillingConsole, never here.
 */

export const CONSUMPTION_TAX_RATE = 0.1

/* ─────────────────────────── 請求（売掛）一覧 ─────────────────────────── */

export type PaymentStatus = "未発行" | "発行済" | "一部入金" | "入金済" | "滞留"

export interface Invoice {
  /** 請求番号 */
  no: string
  /** 荷主（取引先） */
  shipper: string
  /** 締め（請求月・締め日） */
  closing: string
  /** この請求に含まれる運行件数 */
  trips: number
  /** 税抜金額（円） */
  net: number
  /** 消費税（円） */
  tax: number
  status: PaymentStatus
  /** 支払期日 */
  dueDate: string
  /** 滞留日数（期日超過日数。0 以下は期日前/当日） */
  overdueDays: number
  /** 燃料サーチャージ未適用フラグ */
  surchargeMissing?: boolean
}

/** 税込（請求額）。net + tax を信用せず常に再計算したい場面用の派生値。 */
export function grossOf(inv: Pick<Invoice, "net" | "tax">): number {
  return inv.net + inv.tax
}

