/* ─────────── 荷主／締めグルーピングのための派生構造（小計つき） ─────────── */

export interface InvoiceGroup {
  shipper: string
  closing: string
  /** グループキー（shipper + closing） */
  key: string
  rows: Invoice[]
  subtotalNet: number
  subtotalTax: number
  subtotalGross: number
  tripCount: number
  /** グループ内に未収（滞留/一部入金/未発行以外で期日超過）があるか */
  hasOverdue: boolean
}

/** 荷主 → 締め の順でグルーピングし、各グループに小計を付与する。 */
export function groupInvoices(invoices: Invoice[]): InvoiceGroup[] {
  const map = new Map<string, InvoiceGroup>()
  for (const inv of invoices) {
    const key = `${inv.shipper}␟${inv.closing}`
    let g = map.get(key)
    if (!g) {
      g = {
        shipper: inv.shipper,
        closing: inv.closing,
        key,
        rows: [],
        subtotalNet: 0,
        subtotalTax: 0,
        subtotalGross: 0,
        tripCount: 0,
        hasOverdue: false,
      }
      map.set(key, g)
    }
    g.rows.push(inv)
    g.subtotalNet += inv.net
    g.subtotalTax += inv.tax
    g.subtotalGross += grossOf(inv)
    g.tripCount += inv.trips
    if (inv.overdueDays > 0) g.hasOverdue = true
  }
  return Array.from(map.values())
}

/* ─────────────────────────── 売掛・請求 KPI ─────────────────────────── */

export interface BillingKpis {
  /** 当月請求額（税込・当月締め分） */
  billedThisMonth: number
  /** 売掛金残高（発行済で未入金・一部入金・滞留の税込合計） */
  receivable: number
  /** 未収（滞留・期日超過分の税込合計） */
  overdue: number
  /** 入金済（当期入金消込済みの税込合計） */
  collected: number
  /** 未発行の請求件数 */
  unissuedCount: number
  /** 滞留している請求件数 */
  overdueCount: number
}

export function computeKpis(invoices: Invoice[]): BillingKpis {
  let billedThisMonth = 0
  let receivable = 0
  let overdue = 0
  let unissuedCount = 0
  let overdueCount = 0

  for (const inv of invoices) {
    const gross = grossOf(inv)
    if (inv.closing.startsWith("2024年6月")) billedThisMonth += gross
    if (inv.status === "発行済" || inv.status === "一部入金" || inv.status === "滞留") {
      receivable += gross
    }
    if (inv.status === "滞留" || inv.overdueDays > 0) {
      overdue += gross
      overdueCount += 1
    }
    if (inv.status === "未発行") unissuedCount += 1
  }

  // 入金済（当期に消し込んだ実績。デモ用の固定実績）。
  const collected = 3_586_300

  return { billedThisMonth, receivable, overdue, collected, unissuedCount, overdueCount }
}

/* ─────────────────────── 運賃明細（運賃計算） ─────────────────────── */

export type FreightLineKind = "add" | "subtract"

export interface FreightLine {
  /** 区分見出しか明細行か小計行か */
  type?: "line" | "subtotal" | "heading"
  label: string
  /** 正の値で渡し、控除は kind="subtract" で表現 */
  amount?: number
  kind?: FreightLineKind
  note?: string
}

export interface FreightCase {
  /** 運行／案件番号 */
  no: string
  shipper: string
  /** 区間 */
  route: string
  /** 車種 */
  vehicle: string
  /** 運賃形態 */
  basis: "距離制" | "車建て" | "個建て"
  /** 明細行（順序どおり） */
  lines: FreightLine[]
  /** 税抜小計（lines の add/subtract を畳んだ値） */
  net: number
  /** 消費税 */
  tax: number
  /** 請求額（税込） */
  gross: number
}

/** lines（add/subtract）を畳んで税抜小計を出し、消費税・税込を付与する。 */
export function settleFreight(
  base: Omit<FreightCase, "net" | "tax" | "gross">
): FreightCase {
  const net = base.lines.reduce((sum, l) => {
    if (l.type === "heading" || l.amount == null) return sum
    if (l.type === "subtotal") return sum // 小計行は表示用、二重計上しない
    return l.kind === "subtract" ? sum - Math.abs(l.amount) : sum + l.amount
  }, 0)
  const tax = Math.round(net * CONSUMPTION_TAX_RATE)
  return { ...base, net, tax, gross: net + tax }
}

export const FREIGHT_CASE: FreightCase = settleFreight({
